#!/usr/bin/env node
process.env.TZ="UTC";
import {mkdtempSync,mkdirSync,writeFileSync,readdirSync,rmSync}from"node:fs";import{tmpdir}from"node:os";import{join}from"node:path";import{pathToFileURL}from"node:url";
const root=process.env.AEON_MEMORY_TS_BASELINE;if(!root)throw Error("AEON_MEMORY_TS_BASELINE required");const {LocalMemoryCleaner}=await import(pathToFileURL(join(root,"src/utils/memory-cleaner.ts")));
const base=mkdtempSync(join(tmpdir(),"aeon-memory-cleaner-"));for(const d of["conversations","records"]){mkdirSync(join(base,d),{recursive:true});for(const f of["2026-07-10.jsonl","2026-07-11.json","2026-07-12.jsonl","notes.jsonl","bad.txt"])writeFileSync(join(base,d,f),f);}
const calls=[];const vectorStore={countL0:async()=>51,countL1:async()=>21,deleteL0Expired:async c=>(calls.push(["l0",c]),7),deleteL1Expired:async c=>(calls.push(["l1",c]),3)};const logs=[];const cleaner=new LocalMemoryCleaner({baseDir:base,retentionDays:2,cleanTime:"03:00",vectorStore,logger:{info:m=>logs.push(m),debug(){},warn(){},error(){}}});await cleaner.runOnce(Date.parse("2026-07-13T12:00:00.000Z"));const tree={conversations:readdirSync(join(base,"conversations")).sort(),records:readdirSync(join(base,"records")).sort()};rmSync(base,{recursive:true,force:true});writeFileSync(process.env.AEON_MEMORY_ORACLE_OUTPUT||new URL("./cleaner_oracle.json",import.meta.url).pathname,JSON.stringify({tree,calls,summary:logs.at(-1)},null,2)+"\n");
